module reset_controller (
    input wire clk,
    input wire rst,
    output reg out
);

always @(posedge clk or posedge rst) begin
    if (rst) begin
        out <= 0;
    end else begin
        out <= ~out;
    end
end

  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        out <= 1;
      end else begin
        out <= out & 1'b1;
      end;
    end
  end

endmodule

